changeSet.sql:
DO $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'sipro_run_status') THEN
        CREATE TYPE sipro_run_status AS ENUM ('STARTED','SUCCESS','FAILED','INCOMPLETE');
    END IF;
END
$$;

CREATE TABLE IF NOT EXISTS sipro_lz_ingestion_run ( run_id BIGSERIAL PRIMARY KEY, tabla_origen TEXT NOT NULL, id_parametro INTEGER NOT NULL REFERENCES sipro_parametros_tablas_lz(id_parametro), period_year INTEGER NOT NULL, period_month INTEGER NOT NULL, parametro_version INTEGER NOT NULL, parametro_estado TEXT NOT NULL, columnas_seleccionadas TEXT NOT NULL, filtros TEXT, query_hash TEXT NOT NULL, lz_row_count BIGINT, pg_stg_row_count BIGINT, pg_final_row_count BIGINT, status TEXT NOT NULL DEFAULT 'STARTED', message TEXT, started_at TIMESTAMPTZ NOT NULL DEFAULT now(), ended_at TIMESTAMPTZ, overwrite_allowed BOOLEAN NOT NULL DEFAULT true );
CREATE INDEX IF NOT EXISTS ix_sipro_lz_run_lookup ON sipro_lz_ingestion_run (tabla_origen, period_year, period_month, started_at DESC);
-- Garantiza unicidad de exito por tabla+periodo (el guard de negocio en DB) CREATE UNIQUE INDEX IF NOT EXISTS ux_sipro_lz_run_success_month ON sipro_lz_ingestion_run (tabla_origen, period_year, period_month) WHERE status = 'SUCCESS';

changeSet.rollback:
DELETE FROM sipro_parametros_tablas_lz
WHERE tabla_origen = 'mdm_zona_mdm_datos_generales_clientes'
  AND estado = 'ACTIVO' AND version = 1;

changeSet.sql:
DO $$ BEGIN -- Solo actuar si el tipo de la columna es el enum IF EXISTS ( SELECT 1 FROM information_schema.columns WHERE table_name = 'sipro_lz_ingestion_run' AND column_name = 'status' AND udt_name = 'sipro_run_status' ) THEN -- Eliminar el indice parcial que referencia el tipo enum DROP INDEX IF EXISTS ux_sipro_lz_run_success_month;
-- Cambiar tipo de columna a TEXT (cast implicito desde enum) ALTER TABLE sipro_lz_ingestion_run ALTER COLUMN status TYPE TEXT USING status::TEXT;
-- Recrear el indice parcial usando TEXT CREATE UNIQUE INDEX IF NOT EXISTS ux_sipro_lz_run_success_month ON sipro_lz_ingestion_run (tabla_origen, period_year, period_month) WHERE status = 'SUCCESS'; END IF; END $$;

DO $$
BEGIN
    -- ══════════════════════════════════════════════════════
    -- 1) sipro_lz_ingestion_run — PARTITION BY RANGE (started_at)
    -- ══════════════════════════════════════════════════════
    IF EXISTS (
        SELECT 1 FROM pg_partitioned_table
        WHERE partrelid = 'sipro_lz_ingestion_run'::regclass
    ) THEN
        -- DEFAULT partition
        IF NOT EXISTS (
            SELECT 1 FROM pg_class c
            JOIN pg_inherits i ON c.oid = i.inhrelid
            WHERE i.inhparent = 'sipro_lz_ingestion_run'::regclass
              AND c.relname = 'sipro_lz_ingestion_run_default'
        ) THEN
            CREATE TABLE sipro_lz_ingestion_run_default
                PARTITION OF sipro_lz_ingestion_run DEFAULT;
            RAISE NOTICE 'Created DEFAULT partition for sipro_lz_ingestion_run';
        END IF;

        -- Secuencia para run_id (auto-increment)
        CREATE SEQUENCE IF NOT EXISTS sipro_lz_ingestion_run_run_id_seq;
        PERFORM setval('sipro_lz_ingestion_run_run_id_seq',
            GREATEST(COALESCE((SELECT MAX(run_id) FROM sipro_lz_ingestion_run), 0), 1));
        ALTER TABLE sipro_lz_ingestion_run
            ALTER COLUMN run_id SET DEFAULT nextval('sipro_lz_ingestion_run_run_id_seq');

        -- Index de busqueda (no unique — particionada no soporta unique sin partition key)
        CREATE INDEX IF NOT EXISTS ix_sipro_lz_run_lookup
            ON sipro_lz_ingestion_run (tabla_origen, period_year, period_month, started_at DESC);

        RAISE NOTICE 'sipro_lz_ingestion_run: partitioned setup complete';
    END IF;

    -- ══════════════════════════════════════════════════════
    -- 2) sipro_lz_mdm_datos_generales_clientes — PARTITION BY LIST (ingestion_run_id)
    -- ══════════════════════════════════════════════════════
    IF EXISTS (
        SELECT 1 FROM pg_partitioned_table
        WHERE partrelid = 'sipro_lz_mdm_datos_generales_clientes'::regclass
    ) THEN
        IF NOT EXISTS (
            SELECT 1 FROM pg_class c
            JOIN pg_inherits i ON c.oid = i.inhrelid
            WHERE i.inhparent = 'sipro_lz_mdm_datos_generales_clientes'::regclass
              AND c.relname = 'sipro_lz_mdm_datos_generales_clientes_default'
        ) THEN
            CREATE TABLE sipro_lz_mdm_datos_generales_clientes_default
                PARTITION OF sipro_lz_mdm_datos_generales_clientes DEFAULT;
            RAISE NOTICE 'Created DEFAULT partition for sipro_lz_mdm_datos_generales_clientes';
        END IF;
    END IF;

    -- ══════════════════════════════════════════════════════
    -- 3) sipro_lz_mdm_datos_generales_clientes_stg — PARTITION BY LIST (ingestion_run_id)
    -- ══════════════════════════════════════════════════════
    IF EXISTS (
        SELECT 1 FROM pg_partitioned_table
        WHERE partrelid = 'sipro_lz_mdm_datos_generales_clientes_stg'::regclass
    ) THEN
        IF NOT EXISTS (
            SELECT 1 FROM pg_class c
            JOIN pg_inherits i ON c.oid = i.inhrelid
            WHERE i.inhparent = 'sipro_lz_mdm_datos_generales_clientes_stg'::regclass
              AND c.relname = 'sipro_lz_mdm_datos_generales_clientes_stg_default'
        ) THEN
            CREATE TABLE sipro_lz_mdm_datos_generales_clientes_stg_default
                PARTITION OF sipro_lz_mdm_datos_generales_clientes_stg DEFAULT;
            RAISE NOTICE 'Created DEFAULT partition for sipro_lz_mdm_datos_generales_clientes_stg';
        END IF;
    END IF;

END $$;

changeSet.rollback:
DROP TABLE IF EXISTS sipro_lz_ingestion_run_default;
DROP TABLE IF EXISTS sipro_lz_mdm_datos_generales_clientes_default;
DROP TABLE IF EXISTS sipro_lz_mdm_datos_generales_clientes_stg_default;

changeSet.sql:
ALTER TABLE sipro_parametros_tablas_lz ADD COLUMN IF NOT EXISTS id_tabla INTEGER; ALTER TABLE sipro_parametros_tablas_lz ADD COLUMN IF NOT EXISTS query_sql TEXT; ALTER TABLE sipro_parametros_tablas_lz ADD COLUMN IF NOT EXISTS fecha_creacion TIMESTAMP; ALTER TABLE sipro_parametros_tablas_lz ADD COLUMN IF NOT EXISTS fecha_modificacion TIMESTAMP; ALTER TABLE sipro_parametros_tablas_lz ALTER COLUMN estado SET DEFAULT 'ACTIVO';
DO $$ BEGIN IF EXISTS ( SELECT 1 FROM information_schema.columns WHERE table_name = 'sipro_parametros_tablas_lz' AND column_name = 'created_at' ) THEN UPDATE sipro_parametros_tablas_lz SET fecha_creacion = COALESCE(fecha_creacion, created_at, now()), fecha_modificacion = COALESCE(fecha_modificacion, created_at, now()) WHERE fecha_creacion IS NULL OR fecha_modificacion IS NULL; ELSE UPDATE sipro_parametros_tablas_lz SET fecha_creacion = COALESCE(fecha_creacion, now()), fecha_modificacion = COALESCE(fecha_modificacion, now()) WHERE fecha_creacion IS NULL OR fecha_modificacion IS NULL; END IF; END $$;
DO $$ BEGIN IF EXISTS ( SELECT 1 FROM information_schema.columns WHERE table_name = 'sipro_parametros_tablas_lz' AND column_name = 'tabla_origen' ) THEN UPDATE sipro_parametros_tablas_lz p SET id_tabla = c.id_tabla FROM sipro_lz_catalogo_tablas c WHERE p.id_tabla IS NULL AND LOWER(TRIM(c.tabla_origen)) = LOWER(TRIM(p.tabla_origen)); END IF; END $$;
DO $$ BEGIN IF EXISTS ( SELECT 1 FROM information_schema.columns WHERE table_name = 'sipro_parametros_tablas_lz' AND column_name = 'tabla_origen' ) AND EXISTS ( SELECT 1 FROM information_schema.columns WHERE table_name = 'sipro_parametros_tablas_lz' AND column_name = 'columnas_seleccionadas' ) THEN UPDATE sipro_parametros_tablas_lz SET query_sql = 'SELECT ' || columnas_seleccionadas || ' FROM ' || tabla_origen || CASE WHEN filtros IS NOT NULL AND BTRIM(filtros) <> '' THEN ' WHERE ' || filtros ELSE '' END WHERE (query_sql IS NULL OR BTRIM(query_sql) = '') AND columnas_seleccionadas IS NOT NULL AND tabla_origen IS NOT NULL; END IF; END $$;
DO $$ BEGIN IF NOT EXISTS ( SELECT 1 FROM information_schema.table_constraints tc JOIN information_schema.key_column_usage kcu ON tc.constraint_schema = kcu.constraint_schema AND tc.constraint_name = kcu.constraint_name WHERE tc.table_name = 'sipro_parametros_tablas_lz' AND tc.constraint_type = 'FOREIGN KEY' AND kcu.column_name = 'id_tabla' ) THEN ALTER TABLE sipro_parametros_tablas_lz ADD CONSTRAINT fk_sipro_parametros_tablas_lz_id_tabla FOREIGN KEY (id_tabla) REFERENCES sipro_lz_catalogo_tablas(id_tabla); END IF; END $$;
CREATE INDEX IF NOT EXISTS ix_sipro_params_lz_id_tabla_estado ON sipro_parametros_tablas_lz (id_tabla, estado, version DESC);
DO $$ BEGIN IF NOT EXISTS (SELECT 1 FROM sipro_parametros_tablas_lz WHERE id_tabla IS NULL) AND EXISTS ( SELECT 1 FROM information_schema.columns WHERE table_name = 'sipro_parametros_tablas_lz' AND column_name = 'id_tabla' ) THEN ALTER TABLE sipro_parametros_tablas_lz ALTER COLUMN id_tabla SET NOT NULL; END IF; IF NOT EXISTS (SELECT 1 FROM sipro_parametros_tablas_lz WHERE query_sql IS NULL) AND EXISTS ( SELECT 1 FROM information_schema.columns WHERE table_name = 'sipro_parametros_tablas_lz' AND column_name = 'query_sql' ) THEN ALTER TABLE sipro_parametros_tablas_lz ALTER COLUMN query_sql SET NOT NULL; END IF; END $$;
ALTER TABLE sipro_lz_ingestion_run ADD COLUMN IF NOT EXISTS id_tabla INTEGER;
DO $$ BEGIN UPDATE sipro_lz_ingestion_run r SET id_tabla = p.id_tabla FROM sipro_parametros_tablas_lz p WHERE r.id_tabla IS NULL AND r.id_parametro = p.id_parametro; END $$;
DO $$ BEGIN IF NOT EXISTS ( SELECT 1 FROM information_schema.table_constraints tc JOIN information_schema.key_column_usage kcu ON tc.constraint_schema = kcu.constraint_schema AND tc.constraint_name = kcu.constraint_name WHERE tc.table_name = 'sipro_lz_ingestion_run' AND tc.constraint_type = 'FOREIGN KEY' AND kcu.column_name = 'id_tabla' ) THEN ALTER TABLE sipro_lz_ingestion_run ADD CONSTRAINT fk_sipro_lz_ingestion_run_id_tabla FOREIGN KEY (id_tabla) REFERENCES sipro_lz_catalogo_tablas(id_tabla); END IF; END $$;
CREATE INDEX IF NOT EXISTS ix_sipro_lz_run_lookup_id_tabla ON sipro_lz_ingestion_run (id_tabla, period_year, period_month, started_at DESC);
DO $$ BEGIN IF NOT EXISTS (SELECT 1 FROM sipro_lz_ingestion_run WHERE id_tabla IS NULL) AND EXISTS ( SELECT 1 FROM information_schema.columns WHERE table_name = 'sipro_lz_ingestion_run' AND column_name = 'id_tabla' ) THEN ALTER TABLE sipro_lz_ingestion_run ALTER COLUMN id_tabla SET NOT NULL; END IF; END $$;

changeSet.rollback:
DROP INDEX IF EXISTS ix_sipro_lz_run_lookup_id_tabla;
ALTER TABLE sipro_lz_ingestion_run DROP CONSTRAINT IF EXISTS fk_sipro_lz_ingestion_run_id_tabla;
ALTER TABLE sipro_lz_ingestion_run DROP COLUMN IF EXISTS id_tabla;
DROP INDEX IF EXISTS ix_sipro_params_lz_id_tabla_estado;
ALTER TABLE sipro_parametros_tablas_lz DROP CONSTRAINT IF EXISTS fk_sipro_parametros_tablas_lz_id_tabla;
ALTER TABLE sipro_parametros_tablas_lz DROP COLUMN IF EXISTS fecha_modificacion;
ALTER TABLE sipro_parametros_tablas_lz DROP COLUMN IF EXISTS fecha_creacion;
ALTER TABLE sipro_parametros_tablas_lz DROP COLUMN IF EXISTS query_sql;
ALTER TABLE sipro_parametros_tablas_lz DROP COLUMN IF EXISTS id_tabla;

